@app.route("/scan_today")
def scan_today():
    address=request.args.get("address",DEF_WALLET)
    hours=int(request.args.get("hours","24"))
    since_ts=int(time.time())-(hours*3600)
    MORALIS_KEY="eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJub25jZSI6IjBiYjJjMGZjLTRiMmItNDkzYy1iZGNkLWJhNWU0NDNiYmI1MCIsIm9yZ0lkIjoiNTEzMjk5IiwidXNlcklkIjoiNTI4MjA0IiwidHlwZUlkIjoiZjQ1MzA2ZWYtZWUzOC00ZWZkLWFhNjYtMjg2YWMxYzhmMDE5IiwidHlwZSI6IlBST0pFQ1QiLCJpYXQiOjE3Nzc0MTMxNzQsImV4cCI6NDkzMzE3MzE3NH0.0HADMCTCV7FL_59JQ6-di_yO-bEH9sYZUn6bir2w7J8"
    CHAIN="bsc"
    try:
        # Balance via Moralis
        bal_url=f"https://deep-index.moralis.io/api/v2.2/wallets/{address}/tokens?chain={CHAIN}&token_addresses%5B0%5D={USDT_CONTRACT}"
        bal_r=requests.get(bal_url,headers={"X-API-Key":MORALIS_KEY},timeout=15)
        bal_d=bal_r.json()
        balance=0.0
        for t in bal_d.get("result",[]):
            if t.get("token_address","").lower()==USDT_CONTRACT.lower():
                balance=float(t.get("balance_formatted",0))
                break

        # Transfers via Moralis
        tx_url=f"https://deep-index.moralis.io/api/v2.2/{address}/erc20/transfers?chain={CHAIN}&contract_addresses%5B0%5D={USDT_CONTRACT}&limit=100&order=DESC"
        tx_r=requests.get(tx_url,headers={"X-API-Key":MORALIS_KEY},timeout=20)
        tx_d=tx_r.json()

        transfers=tx_d.get("result",[])
        today_txs=[]; total_in=0.0; addr_lower=address.lower()

        for tx in transfers:
            # block_timestamp: "2026-06-28T12:34:56.000Z"
            from datetime import timezone
            ts_str=tx.get("block_timestamp","")
            try:
                dt=datetime.strptime(ts_str,"%Y-%m-%dT%H:%M:%S.%fZ").replace(tzinfo=timezone.utc)
                ts=int(dt.timestamp())
            except:
                continue
            if ts<since_ts: continue
            if tx.get("to_address","").lower()!=addr_lower: continue
            amt=float(tx.get("value_decimal",0))
            total_in+=amt
            today_txs.append({
                "hash":tx.get("transaction_hash",""),
                "amount":round(amt,4),
                "time":datetime.fromtimestamp(ts).strftime("%d.%m %H:%M"),
                "from":tx.get("from_address","")[:16]+"..."
            })

        return jsonify({"ok":True,"total_incoming":round(total_in,4),
            "transactions":today_txs[:20],"count":len(today_txs),
            "balance":round(balance,4),
            "date":datetime.now().strftime("%d.%m.%Y"),"hours_scanned":hours})
    except Exception as e:
        return jsonify({"ok":False,"error":str(e)}),500
@app.route("/preview",methods=["POST","OPTIONS"])
def preview():
    if request.method=="OPTIONS": return jsonify({})
    try:
        data=request.get_json(force=True,silent=True)or{}
        pct=float(data.get("pct",2.30))
        ds=str(data.get("date",(datetime.now()-timedelta(days=1)).strftime("%d.%m.%Y")))
        return Response(make_poster(pct,ds,extract_coords(data)),mimetype="image/png")
    except Exception as e:
        return jsonify({"error":str(e)}),500

