@app.route("/send",methods=["POST","OPTIONS"])
def send():
    if request.method=="OPTIONS": return jsonify({})
    try:
        data=request.get_json(force=True,silent=True)or{}
        pct=float(data.get("pct",0)); gained=float(data.get("gained",0))
        kapital=float(data.get("kapital",0)); note=str(data.get("note",""))
        ds=str(data.get("date",(datetime.now()-timedelta(days=1)).strftime("%d.%m.%Y"))); ts=str(data.get("time",""))
        sg="+" if pct>=0 else ""; em="\U0001f4c8" if pct>=0 else "\U0001f4c9"
        # Custom Caption direkt nutzen falls vorhanden
        custom_caption=str(data.get("custom_caption","")).strip()
        if custom_caption:
            cap=custom_caption
        else:
            cap=f"{em} *OneTrade \u2013 T\u00e4gliche Aussch\u00fcttung*\n\n"
            cap+=f"\U0001f4c5 *Datum:* {ds} | {ts} Uhr\n"+"\u2501"*17+"\n"
            cap+=f"\U0001f4b0 *Tagesgewinn:* `{sg}{pct:.4f}%`\n"
            if gained>0: cap+=f"\U0001f4b5 *Ausgesch\u00fcttet:* `{gained:,.2f} USDT`\n"
            if kapital>0: cap+=f"\U0001f3e6 *Eingesetztes Kapital:* `{kapital:,.2f} USDT`\n"
            cap+="\u2501"*17+"\n"
            if note: cap+=f"\U0001f4dd {note}\n"+"\u2501"*17+"\n"
            cap+="_Powered by OneTrade AI System_\n_Vergangene Ergebnisse sind keine Garantie f\u00fcr die Zukunft._"
        png=make_poster(pct,ds,extract_coords(data))
        r=requests.post(f"https://api.telegram.org/bot{T}/sendPhoto",
            files={"photo":("p.png",png,"image/png")},
            data={"chat_id":G,"caption":cap,"parse_mode":"Markdown"},timeout=30)
        d=r.json()
        if d.get("ok"): return jsonify({"ok":True,"with_image":True})
        r2=requests.post(f"https://api.telegram.org/bot{T}/sendMessage",
            json={"chat_id":G,"text":cap,"parse_mode":"Markdown","disable_web_page_preview":True},timeout=15)
        return jsonify({"ok":r2.json().get("ok"),"with_image":False})
    except Exception as e:
        return jsonify({"ok":False,"error":str(e)}),500

